	('82030000125607', 'บริษัท สแน็คทูโก (เอเชีย) จำกัด', 'บริษัท เอสทูจี (888) จำกัด', '-ผลิตและจำหน่าย ขนมขบเคี้ยว-', '168/9', '0', 'ฉลองกรุง 31', '-', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '01001', 63940000, 26, 2821, '1544', 'น.10(1)-1/2560-นนล.', 'Thailand'),
	('82030000225498', 'บริษัท ซีพีแรม จำกัด', 'บริษัท ซีพีแรม จำกัด', 'ผลิตเบเกอรี่', '153,154,161', '0', 'ฉลองกรุง 31', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '01001', 0, 1353, 8528, '1541', 'น.10(1)-2/2549-นนล.', 'Thailand'),
	('72030000125393', 'บริษัท เอส แอนด์ พี ซินดิเคท จำกัด (มหาชน)', 'บริษัท เอส แอนด์ พี ซินดิเคท จำกัด (มหาชน)', 'ผลิตปอเปี้ยะสดแช่แข็ง ซาโมซ่าแช่แข็ง แผ่นปอเปี้ยะแช่แข็ง เส้นมักโรนี ผลิตภัณฑ์แป้งสาลี ไอซิ่ง ผงฟู สีผสมอาหาร อาหารสำเร็จรูปแช่แข็งชนิดบรรจุกล่องและถุง และอาหาร กึ่งสำเร็จรูปแช่เย็น เช่น อาหารคาว ของหวาน ซอสปรุงรส เครื่องแกง และน้ำจิ้มต่างๆ, ผลิตไฟฟ้าจากแสงอาทิตย์ กำลังการผลิต 532.56 กิโลวัตต์  เพื่อใช้เป็นระบบสาธารณูปโภคภายในโรงงาน', '65/4-5', '4', NULL, 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '01003', 2011850000, 281, 738, '1549', 'น.10(3)-1/2539-ญนล.', 'Thailand'),
	('82030002725636', 'บริษัท เมย์คราวน์ ฟู้ดส์ จำกัด', 'บริษัท เมย์คราวน์ ฟู้ดส์ จำกัด', 'ผลิตน้ำเชื่อมอุตสาหกรรม, น้ำตาลผสมแบบผงหรือก้อนสำหรับอุตสาหกรรม', '6', '0', 'ฉลองกรุง 31', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '01101', 49860000, 26, 1001, NULL, 'น.11(1)-27/2563-นนล.', 'Thailand'),
	('72030000125450', 'บริษัท เขาช่องอุตสาหกรรม 1979 จำกัด', 'บริษัท เขาช่องอุตสาหกรรม 1979 จำกัด', 'ผลิตกาแฟสำเร็จรูป กาแฟคั่วและบด กาแฟปรุงสำเร็จชนิดผงและสินค้าที่เกี่ยวข้องกับกาแฟทุกชนิด', '100', '4', '-', '-', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '01202', 402540000, 4, 325, '1549', 'น.12(2)-1/2545-ญนล.', 'Thailand'),
	('72030000125484', 'บริษัท มอนเดลีซ อินเตอร์เนชันแนล (ประเทศไทย) จำกัด', 'บริษัท มอนเดลีซ อินเตอร์เนชันแนล (ประเทศไทย) จำกัด', 'ผลิต CANDY, GUM AND COMPRESSED MINTS, ผลิตกระแสไฟฟ้าจากพลังงานแสงอาทิตย์ กำลังการผลิต 620 กิโลวัตต์ เพื่อใช้ในอาคารโรงงาน', '102/1', '4', '-', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '01210', 546000000, 430, 6575, '1543', 'น.12(10)-1/2548-ญนล.', 'Thailand'),
	('82030025425685', 'บริษัท แม็กนั่ม ไอซีซี (ไทยแลนด์) จำกัด', 'บริษัท แม็กนั่ม ไอซีซี (ไทยแลนด์) จำกัด', '1. ผลิต และรับจ้างผลิตไอศกรีม 2. บริการเป็นที่ปรึกษา และให้คำแนะนำเกี่ยวกับด้านบริหารงาน พาณิชยกรรม อุตสาหกรรม การผลิต การตลาด และการจัดจำหน่าย 3. บริการให้เช่าตู้แช่ไอศกรีม เครื่องจักร ยานพาหนะ และอุปกรณ์ที่เกี่ยวข้องกับการผลิต การรับจ้างผลิต การตลาด และการจัดจำหน่ายไอศกรีม รวมทั้งให้เช่าโกดังเก็บสินค้า ที่ดินและอาคารบางส่วนของบริษัท 4. บริการให้ใช้สิทธิในทรัพย์สินทางปัญญา', '38/1', '0', 'ฉลองกรุง 31', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '01211', 23377130000, 350, 13328, NULL, 'น.12(11)-254/2568-นนล.', 'Thailand'),
	('82030000125482', 'บริษัท วี. เมน ฟิลส์ (ประเทศไทย) จำกัด', 'บริษัท วี. เมน ฟิลส์ (ประเทศไทย) จำกัด', 'ซื้อมาขายไป ผลิตหัวน้ำหอม (FRAGRANCES) และ INDUSTRAIL  FRAGRANCE COMPOUND วัตถุปรุงแต่งอาหาร วัถุเจือปนอาหาร วัตถุแต่งกลิ่นรส สีผสมอาหาร เครื่องเทศต่างๆ พืชผักแห้ง ผลิตภัณฑ์จากพืช เครื่องปรุงรส ซอส เครื่องดื่ม อาหารกึ่งสำเร็จรูป หมากฝรั่งและลูกอม น้ำมันปาล์ม ผลิตภัณฑ์กระเทียม และผลิตวัตถุแต่งกลิ่นรส วัตถุที่ใช้ปรุงแต่งรสอาหาร เครื่องปรุงรส เครื่องเทศต่างๆ (FLAVOUR & SEASONING RODUCTIONL)', '182', '0', 'ฉลองกรุง31', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '01302', 1648390000, 152, 520, '2429', 'น.13(2)-1/2548-นนล.', 'Thailand'),
	('72030000125344', 'บริษัท ดาสโก้ จำกัด', 'บริษัท ดาสโก้ จำกัด', 'ผลิตผลิตภัณฑ์ที่ทำจากผ้าทุกชนิด พีวีซี ไนล่อน โพลีเอสเตอร์ เช่น ชุดอุ้มเด็ก ชุดเก้าอี้ รถเข็นเด็ก ชุดเปลเด็กผ้าหุ้มรถเข็นเด็ก ชุดกีฬา กระเป๋าผ้าต่าง ๆ และตัดเย็บเสื้อผ้าสำเร็จรูปทุกชนิด เช่น ชุดกีฬา ชุดเด็กเล็ก ชุดผ้าคลุมตัดผมเสื้อแจ็คเก็ต ซื้อมาขายไปแค็ตตาล็อคสินค้า, ประกอบกิจการผลิตและจำหน่ายรับจ้างการผลิตตลอดจนนำเข้าและส่งออกซึึ่งสินค้าประเภทหน้ากากทุกชนิด เช่น หน้ากากอนามัย หน้ากากที่ใช้ในการผลิตอุตสาหกรรมหน้ากากป้องกันฝุ่นละออง หน้ากากสวมป้องกันความร้อนและเปลวไฟ หน้ากากที่ทำจากผ้าทุกชนิดหน้ากากที่ทำจากผ้าใยเทียมทุกชนิดตลอดจนวัสดุหรือวัตถุดิบที่ใช้ในการผลิตหน้ากาก', '264', '0', 'ฉลองกรุง 31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '02301', 412660000, 165, 224, '1912', 'น.23(1)-1/2534-ญนล.', 'Thailand'),
	('82030000125557', 'บริษัท ดาสโก้ จำกัด', 'บริษัท ดาสโก้ จำกัด', '-ผลิตผลิตภัณฑ์ที่ทำจากผ้าทุกชนิด พีวีขี ไนล่อน โพลีเอสเตอร์ เช่น ชุดอุ้นเด็ก ชุดเก้าอี้ รถเข็นเด็กชุดเปลเด็ก ผ้าหุ่มรถเข็นเด็ก ชุดกีฬา กระเป๋าผ้าต่างๆและตัดเย็บเสื้อผ้าสำเร็บรูปทุกนิด เช่น ชุดกีฬา ชุดเด็กเล็กชุดผ้าคลุมตัดผม เสื้อแจ็คเก็ต ซื้อมาขายไปแค็ดตาล็อคสินค้า-', '286', '0', 'ฉลองกรุง 31', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '02301', 285430000, 500, 239, '1912', 'น.23(1)-1/2555-นนล.', 'Thailand'),
	('82030100125606', 'บริษัท อีเกิ้ล สปีด อินดัสตรี้ (ประเทศไทย) จำกัด', 'บริษัท อีเกิ้ล สปีด อินดัสตรี้ (ประเทศไทย) จำกัด', 'การซื้อมาขายไป ชุดสกี ชุดกอล์ฟ เสื้อกันฝนและกางเกงกันฝน หมวก ถุงนอน กระเป๋าและหมอน รวมถึงซื้อมาขายไป วัตถุดิบ และเครื่องจักรที่เกี่ยวเนื่องในการผลิตสินค้าดังกล่าวและคลังเก็บสินค้าดังกล่าวข้างต้นซื้อมาขายไป ผลิตและจำหน่ายเรือยาง ที่นอนยาง ผลิตภัณฑ์ยางที่ลมเป่าทุกชนิด เสื้อผ้าสำเร็จรูป กระเป๋า เป้ เต้นท์ ถุงนอน หมอน มุ้ง หมวก พร้อมทั้งวัสดุอุปกรณ์ อะไหล่เกี่ยวกับประกอบธุรกิจบริการรับเป็นที่ปรึกษาและให้คำแนะนำด้านบริการ ซื้อมาขายไป เครื่องจักรที่ใช้ในการผลิตหรือเกี่ยวเนื่องกับการผลิตของโรงงานทั้งหมด ซื้อมา ขายไป วัสดุอุปกรณ์ที่ใช้ในการผลิตผ้าเคลือบ TPU FILM ทุกชนิด เช่น กาว กาวยาง RESIN กระดาษอัดลาย ซื้อมาขายไปบรรจุภัณฑ์อุปกรณ์ที่ใช้บรรจุ ถุง กล่อง ป้ายชื่อ ฉลากทุกชนิด', '270', '0', 'ฉลองกรุง 31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '02303', 44580000, 115, 131, NULL, 'น.23(3)-1/2560-นนล.', 'Thailand'),
	('82030005425663', 'บริษัท แอดเวนเจอร์ ดีเอ็นเอ จำกัด', 'บริษัท แอดเวนเจอร์ ดีเอ็นเอ จำกัด', 'การซื้อมาขายไป ชุดสกี ชุดกอล์ฟ เสื้อกันฝนและกางเกงกันฝน หมวก ถุงนอน กระเป๋าและหมอน รวมถึงซื้อมาขายไป วัตถุดิบและเครื่องจักรเกี่ยวเนื่องในการผลิตสินค้าดังกล่าว และคลังเก็บสินค้าดังกล่าวข้างต้นซื้อมาขายไป ผลิตและจำหน่ายเรือยาง ที่นอนยาง ผลิตภัณฑ์ยางที่ลมเป่าทุกชนิด เสื้อผ้าสำเร็จรูป กระเป๋า เป้ เต้นท์ ถุงนอน หมอน มุ้ง หมวก พร้อมทั่้งวัสดุอุปกรณ์ อะไหล่เกี่ยวกับประกอบธุรกิจบริการรับเป็นที่ปรึกษาแนะนำด้านบริการ ซื้อมาขายไป เครื่องจักรที่ใช้ในการผลิตหรือเกี่ยวเนื่องกับการผลิตของโรงงานทั้งหมด ซื้อมาขายไป วัสดุอุปกรณ์ที่ใช้ในการผลิตผ้าเคลือบ TPU FILM ทุกชนิดเช่น กาวยาง RESIN กระดาษอัดลาย ซื้อมาขายไปบรรจุภัณฑ์อุปกรณ์ที่ใช้บรรจุ ถง กล่อง ป้ายชื่อ ฉลากทุกชนิด, ซื้อมาขายไป Platinum (Pt) Palladium (Pd) Rethenium (Ru) Rhodium (Rh) Osmium (Os) Iridium (Ir) Gold (Au)', '270', '0', 'ฉลองกรุง31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '02303', 9000000, 44, 260, NULL, 'น.23(3)-54/2566-นนล.', 'Thailand'),
	('82030015625682', 'บริษัท ไอ-เจอร์ซีย์ จำกัด', 'บริษัท ไอ-เจอร์ซีย์ จำกัด', 'ผลิตชุดกีฬา เสื้อ กางเกง', '13', '4', 'ฉลองกรุง', '13 Mu 4 soi Chalongkrung 31 Chalongkrung rd', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '02400', 7500000, 34, 143, NULL, 'น.24-156/2568-นนล.', 'Thailand'),
	('82030000125334', 'บริษัท ไทยมาร์โซล จำกัด', 'บริษัท ไทยมาร์โซล จำกัด', 'ผลิตแห-อวน (น้ำเค็ม),ตาข่ายสำหรับใช้ในสงคราม, BRAIDED CORDS (เชือกพลาสติกเชือกไนล่อน และเชือกชนิดต่างๆ) และเส้นใยสังเคราะห์ต่างๆ (POLYETHYLENE POLYPROPYLENE, POLYESTER NYLON)  PLASTIC SHEET PAPER LAMINATE PAPER LAMINATE รับจ้างผลิต  BRAIDED CORDS (เชือกพลาสติก เชือกไนล่อน และเชือกชนิดต่างๆ)  PLASTIC SHEET PAPER LAMINATE หลอมเศษพลาสติกให้เป็นเม็ดพลาสติก', '202', '0', 'ฉลองกรุง 31 นิคมอุตสาหกรรมลาดกระบัง เขตป', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '02601', 262050000, 153, 2804, '2899', 'น.26(1)-1/2533-ญนล.', 'Thailand'),
	('82030100125556', 'บริษัท วาส อินเตอร์เนชั่นนอล จำกัด', 'บริษัท วาส อินเตอร์เนชั่นนอล จำกัด', '1. ตัดเย็บผลิตภัณฑ์จากหนังและผ้า เช่น เครื่องแต่งกาย กระเป๋า 2. ดัดแปลงและซ่อมแซมเสื้อผ้า รองเท้า เครื่องแต่งกาย 3. ซื้อมาขายไปเสื้อผ้า เครื่องแต่งกาย  รองเท้า กระเป๋า ผลิตภัณฑ์ จากหนังและผ้า อะไหล่รถยนต์ และรถจักรยานยนต์ นำเข้า-ส่งออก จำหน่าย ซื้อมาขายไป เครื่องดนตรี และ อุปกรณ์กีฬาทุกชนิด ทั้งของเก่าและของใหม่ อาหารสด อาหารแห้ง อาหารสำเร็จรูป เครื่องดื่ม เครื่องปรุงรสอาหาร เครื่องเทศ เช่น ข้าว ข้าวโพด ถั่ว งา นำเข้า-ส่งออก จำหน่าย เฟอร์นิเจอร์ เช่น โต๊ะ ตู้ เตียง โซฟา เก้าอี้ ที่นอน ของขวัญ ของแต่งบ้าน ร่ม เครื่องครัว หม้อ กระทะ ถ้วย จาน แก้ว ทั้งเก่าและของใหม่', '193', '0', 'ฉลองกรุง  31', '-', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '02801', 2500000, 21, 100, '5260', 'น.28(1)-1/2555-นนล.', 'Thailand'),
	('72030000325480', 'บริษัท ฮามาจิ อินดัสตรี (ประเทศไทย) จำกัด', 'บริษัท ฮามาจิ อินดัสตรี (ประเทศไทย) จำกัด', 'ผลิตและรับจ้างผลิตชุดชั้นในสุภาพบุรุษ ชุดชั้นในสุภาพสตรี ชุดว่ายน้ำ ชุดกีฬา เสื้อผ้าสำเร็จรูปทุกชนิด อุปกรณ์พยุงร่างกาย เครื่องมือแพทย์ และอุปกรณ์แพทย์', '263', '0', 'ฉลองกรุง 31', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '02801', 33800000, 124, 172, '3311', 'น.28(1)-3/2548-ญนล.', 'Thailand'),
	('82030100125614', 'บริษัท จี แอล โบว์รอน (ไทยแลนด์) จำกัด', 'บริษัท จี แอล โบว์รอน (ไทยแลนด์) จำกัด', 'นำเข้า ส่งออก ซื้อมา-ขายไป เช่า ให้ ขายฝาก ขายปลีก หรือจำหน่ายไปด้วยประการใดๆ ซึ่งสินค้าที่ผลิตขึ้นโดยบริษัทฯ เช่น สินค้าเครื่องนอน เครื่องตกแต่งบ้าน เครื่องตกแต่งรถยนต์ที่ทำจากหนังเฟอร์แกะเฟอร์นิเจอร์เตียงไม้-เหล็ก, ชิ้นส่วนเตียงที่ทำจากพลาสติก โลหะผ้า โพลีเอสเตอร์และอุปกรณ์ของเครื่องนอนทุกชนิด อุปกรณ์เครื่องใช้ภายในบ้าน อุปกรณ์ตกแต่งรถยนต์ ผลิต รับจ้างผลิตและเป็นโรงเก็บสินค้า ที่นอน หมอน ผ้านวม ผ้าคลุมเตียง ตุ๊กตา ถุงมือ เบาะรองนั่งรองเท้าแตะ เสื้อกันหนาว และเครื่องนุ่งห่ม (เฉพาะเพื่อการส่งออก) ผ้า-หนังคลุมเบาะรถยนต์ พรมวางพื้นสิ่งประดับฝาผนัง หนังคลุมถุงกอล์ฟ สิ่งตกแต่งภายในบ้านเรือน สิ่งปูลาด เครื่องเตียง ซึ่งทำด้วยเฟอร์แกะและเศษหนังเฟอร์แกะ หนังเฟอร์ชนิดอื่นๆ รวมทั้งขนสัตว์ ขนอ่อนของนก ขนอ่อนของสัตว์ปีกอื่นๆ ฟองน้ำ ยาง ไม้ พลาสติก โลหะ ผ้าฝ้าย ผ้าขนสัตว์ โพลีเอสเตอร์ และวัสดุสังเคราะห์อื่นๆ ทุกชนิด ผลิต รับจ้างผลิตและจำหน่ายเตียง โต๊ะ ตู้ เก้าอี้ และเครื่องตกแต่งบ้าน (เฟอร์นิเจอร์) ทุกประเภท ซึ่งทำจากผ้าเหล็กพลาสติก ใยสังเคราะห์ ไม้ทุกชนิด ทองเหลือง ทองแดง และโลหะอื่นๆ นำเข้า ส่งออก ค้าปลีก ค้าส่ง ซื้อมาขายไป-เช่า ให้ ขายฝาก เครื่องจักร เครื่องกล เครื่องยนต์ เฟอร์นิเจอร์ และผ้าทุกประเภท รวมทั้งชิ้นส่วนอุปกรณ์ เครื่องมือ อะไหล่ ของสินค้าดังกล่าว ซึ่งใช้ สำหรับผลิตที่นอน เครื่องนอน และเฟอร์นิเจอร์ต่างๆ ซื้อมาขายไป-ให้-นำเข้า-ส่งออก เพื่อการฟอกย้อม ค้าปลีกค้าส่ง สารเคมี เช่น Chem-Acid Brill Blue A Conc Pwd , Chem-Acid Fast Yellow E Conc Pwd , Chem-Acid Scarlet A-R Pwd, Ginasol 68N/Ausapon Aos,Hydrapol BD40, Neosyn Nsa 40, Taurol Se,Verinal DP, Pancrolin N, Calgon T, Secitan D,Chem-Acid Black ACR Conc PWD และน้ำยาย้อมสี สีย้อม และสีแต้มที่ใช้ในอุตสาหกรรมฟอกย้อมหนังเฟอร์แกะ หนังสัตว์อื่นๆ และเสื้อผ้าทุกชนิด รวมทั้ง เครื่องมือเครื่องใช้ อุปกรณ์ที่ใช้ในอุตสาหกรรมฟอกย้อมหนังเฟอร์แกะ หนังสัตว์อื่นๆ และเสื้อผ้า ทุกชนิด ประกอบกิจการขนส่งและขนถ่ายสินค้า ทั้งทางบกทางน้ำทางอากาศ ทั้งภายในประเทศและต่างประเทศ รวมทั้งรับบริการนำของออกจากท่าเรือตามพิธีศุลกากรและการจัดระวางการขนส่งทุกชนิด เป็นนายหน้า ตัวแทน ตัวแทนค้าต่างในกิจการ รับฝากสินค้า และธุรกิจทุกประเภททั้งในประเทศและต่างประเทศ ประกอบกิจการเป็นนายหน้าหรือตัวแทนซื้อขาย จัดซื้อ หรือจัดจำหน่าย หรือจัดหาตลาด รับฝากสินค้า ทั้งในประเทศและต่างประเทศ เพื่อการจำหน่ายสินค้าประเภทเครื่องจักร เครื่องกลเครื่องยนต์ เฟอร์นิเจอร์ และผ้าทุกประเภท ซึ่งผลิตในประเทศหรือนำเข้ามาจากต่างประเทศรวมทั้งชิ้นส่วน อุปกรณ์ เครื่องมือ อะไหล่ของสินค้าดังกล่าว นำเฟอร์นิเจอร์ไปตั้งแสดงสินค้าในงานโชว์ต่างๆ ซ่อม ซักล้าง ตากแห้ง อบ เครื่องนอนทุกชนิด ที่ทำจากขนแกะ ผ้า เส้นใยโพลี เอสเตอร์ และอื่นๆทุกชนิด ผลิต รับจ้างผลิต ซื้อมาขายไป เครื่องนอนทุกชนิดทำจากผ้า ใยสังเคราะห์ และขนสัตว์ของสัตว์ปีกทุกชนิด  ซื้อมาขายไป เครื่องนอนทุกชนิดทำจากยางพารา  นำเข้า ผลิต รับจ้างผลิต จำหน่าย และ ส่งออก สินค้าประเภทเครื่องหนัง เช่น ผลิตภัณฑ์ที่ใช้สำหรับสวมใส่เท้า (Footwear) อาทิ รองเท้า เป็นต้น เสื้อผ้า เครื่องนุ่งหุ่ม กระเป๋า กระเป๋าเดินทาง ผลิตภัณฑ์ที่ใช้สำหรับบ้านเรือน อาทิ เครื่องนอน หมอน พรม เป็นต้น รวมทั้งเป็นโรงเก็บสินค้าเพื่อเก็บสินค้าที่บริษัทผลิตขึ้นตามข้างต้น นำเข้า ผลิต รับจ้างผลิต จำหน่าย และ ส่งออก ผลิตภัณฑ์ที่ใช้สำหรับสวมใส่เท้า (Footwear) อาทิ รองเท้า เป็นต้น ซึ่งทำด้วยหนังเฟอร์แกะ หนังเฟอร์ชนิดอื่นๆ รวมทั้งขนสัตว์ ขนอ่อนของนก ขนอ่อนของสัตว์ปีกอื่นๆ ฟองน้ำ ยาง ผ้าฝ้าย ผ้าขนสัตว์ ผ้าโพลีเอสเตอร์ทุกชนิด และวัสดุสังเคราะห์อื่นทุกชนิด รวมทั้งเป็นโรงเก็บสินค้าเพื่อเก็บสินค้าที่บริษัทผลิตขึ้นตามข้างต้น', '235-236 เขตอุตสาหกรรมส่งออก 3 นิคมอุตสาหกรรมลาดกระบัง', '0', 'ฉลองกรุง 31', '-', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '03100', 99800000, 63, 934, '3610', 'น.31-1/2561-นนล.', 'Thailand'),
	('82030027425626', 'บริษัท บราสปอร์ต (ประเทศไทย) จำกัด', 'บริษัท บราสปอร์ต (ประเทศไทย) จำกัด', 'ผลิตเครื่องหนังทุกชนิดทั้งหนังแท้และหนังเทียม รวมทั้งวัสดุอื่นๆในประเภทเดียวกันและรับจ้างผลิตเครื่องหนังดังกล่าว', '251', '0', 'ฉลองกรุง 31', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '03100', 52400000, 63, 170, NULL, 'น.31-274/2562-นนล.', 'Thailand'),
	('10100000525242', 'บริษัท เอส.ไอ.พี.สยามอินเตอร์แปซิฟิค จำกัด', 'บริษัท เอส.ไอ.พี.สยามอินเตอร์แปซิฟิค จำกัด', 'ทำถุงมือหนังและทำเอ็นเทียมจากหนังสัตว์ ทำอาหารสำเร็จรูปสำหรับสัตว์ เช่น เอ็นเทียม กระดูกเทียม ฯลฯ', '147', NULL, NULL, 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', '02-3605079-83', '03201', 96000000, 119, 2436, '14200', '3-32(1)-5/24', 'Thailand'),
	('72030100125434', 'บริษัท พอยต์ รูสส์ จำกัด', 'บริษัท พอยต์ รูสส์ จำกัด', 'ซื้อมาขายไป นำเข้าส่งออก บรรจุ แบ่งบรรจุ รองเท้า ผลิตรองเท้า เสื้อผ้าสำหรับนักเต้นรำ เสื้อผ้าสำเร็จรูป รวมถึงผลิตภัณฑ์สำเร็จรูป วัสดุและชิ้นส่วนอุปกรณ์เสริมต่าง ๆ ที่ใช้สำหรับทำรองเท้าเต้นรำและชุดเต้นรำ เครื่องประดับ เครื่องแต่งกาย ผลิตภัณฑ์ที่ใช้ประดับเครื่องแต่งกาย ของเลียนแบบเครื่องแต่งกาย ของที่ระลึก ของขวัญ ของชำร่วย กิฟท์ช็อป และผลิตภัณฑ์ของเลียนแบบเครื่องแต่งกาย ที่ทำจากไม้ แก้ว พลาสติก ยาง โลหะ การบรรจุและแบ่งบรรจุผลิตภัณฑ์ดังกล่าวทุกชนิด', '50', '0', 'ฉลองกรุง 31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '03300', 334350000, 419, 527, '7495', 'น.33-1/2543-ญนล.', 'Thailand'),
	('82030000125508', 'บริษัท พอยต์ รูสส์ จำกัด', 'บริษัท พอยต์ รูสส์ จำกัด', 'ซื้อมาขายไป ผลิตรองเท้า เสื้อผ้าสำหรับนักเต้นรำ เสื้อผ้าสำเร็จรูปรวมถึงผลิตภัณฑ์สำเร็จรูป วัสดุและชิ้นส่วนอุปกรณ์เสริมต่างๆ ที่ใช้สำหรับทำรองเท้าเต้นรำและชุดเต้นรำ การนำเข้าและแบ่งบรรจุภัณฑ์ดังกล่าวข้างต้น', '203', '0', 'ฉลองกรุง 31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '03300', 334350000, 454, 666, '7495', 'น.33-1/2550-นนล.', 'Thailand'),
	('82030004325658', 'บริษัท เอเชีย แพ็คเกจจิ้ง กรุ๊ป จำกัด', 'บริษัท เอเชีย แพ็คเกจจิ้ง กรุ๊ป จำกัด', 'ผลิตกล่องเครื่องประดับ แท่นโชว์สินค้า ถุงและกระเป๋าใส่ของมีค่า', '12', '0', 'ฉลองกรุง 31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '03601', 0, 31, 37, NULL, 'น.36(1)-43/2565-นนล.', 'Thailand'),
	('50100198225671', 'บริษัท เอสซีซี เปเปอร์ จำกัด', 'บริษัท เอสซีซี เปเปอร์  จำกัด', 'ผลิตภาชนะบรรจุจากกระดาษทุกชนิดหรือแผ่นกระดาษหรืออัดเศษกระดาษหลายชิ้นเข้าด้วยกันและอัดเศษกระดาษ', '1098', NULL, NULL, 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '03900', 12000000, 5, 71, '17020', 'ก2-39-51/67', 'Thailand'),
	('50100224525672', 'บริษัท โตโย บรรจุภัณฑ์ จำกัด', 'บริษัท โตโย บรรจุภัณฑ์ จำกัด', 'ผลิตและจำหน่ายกล่องกระดาษ ผลิตและจำหน่ายผลิตภัณฑ์จากโฟมและพลาสติกทุกชนิด', '1006', NULL, NULL, 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '03900', 7000000, 14, 72, '17020', 'ก2-39-57/67', 'Thailand'),
	('10100100925383', 'บริษัท กล่องสยามบรรจุภัณฑ์ จำกัด', 'บริษัท กล่องสยามบรรจุภัณฑ์ จำกัด', 'ผลิตกล่องกระดาษ', '1004', NULL, NULL, 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', '01-4821895', '03900', 9000000, 98, 641.6, '17020', '3-39-9/38', 'Thailand'),
	('82030034925683', 'บริษัท ฮอนชู ปริ้นติ้ง (ประเทศไทย) จำกัด', 'บริษัท ฮอนชู ปริ้นติ้ง (ประเทศไทย) จำกัด', 'ผลิต Packaging และบรรจุภัณฑ์เครื่องสำอางค์ (แบบซอง),ผลิต Packagking กล่องกระดาษและกล่องพลาสติก และซองบรรจุภัณฑ์', '249', '0', 'ฉลองกรุง 31', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '03900', 163930000, 5, 149, NULL, 'น.39-349/2568-นนล.', 'Thailand'),
	('82030000125284', 'บริษัท จอห์นสัน แอนด์ จอห์นสัน (ไทย) จำกัด', 'บริษัท จอห์นสัน แอนด์ จอห์นสัน (ไทย) จำกัด', '1. ผลิตสินค้าอุปโภค เช่น ผ้าอนามัย ผ้าอ้อมเด็ก แชมพู ครีมบำรุงผิว แป้ง ก้านสำลีพันปลายไม้ ผลิตยาสำหรับล้างฆ่าเชื้อ เวชภัณฑ์ ชนิดเจล ครีม และน้ำ  ซื้อมาขายไปสินค้าอุปโภค เครื่องมือแพทย์ เวชภัณฑ์ ยาแผนปัจจุบัน ศูนย์บริการทางธุรกิจ โดยบริการด้านการบริหารงาน ด้านการตลาด และบริการหลังการขาย การแบ่งบรรจุ การบรรจุสินค้าอุปโภค เวชภัณฑ์ เครื่องสำอาง เพื่อจำหน่ายในประเทศและต่างประเทศ 2. ให้เช่าที่ดินและอาคาร', '106 นิคมอุตสาหกรรมลาดกระบัง', '4', '-', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04002', 0, 437, 0, '2424', 'น.40(2)-1/2528-นนล.', 'Thailand'),
	('82030000125375', 'บริษัท ทอปปังเอจ (ประเทศไทย) จำกัด', 'บริษัท ทอปปังเอจ (ประเทศไทย) จำกัด', '1. พิมพ์กระดาษที่ใช้กับคอมพิวเตอร์ และบัตรเครดิตต่างๆ  2. ผลิตและรับจ้างผลิตแบบพิมพ์และสิ่งพิมพ์ทุกชนิด 3. รับจ้างพิมพ์และรับจ้างบันทึกข้อมูลในกระดาษ บัตรพลาสติก บัตร IC Chip บัตรโลหะ ป้าย/ฉลาก IC Chip 4. ทำการค้า เครื่องจักร อุปกรณ์ อะไหล่ ของ คอมพิวเตอร์ เครื่องบันทึกเวลา เครื่องควบคุมการเปิดปิดประตู เครื่องอ่านจดจำใบหน้า เครื่องอ่านจดจำป้ายทะเบียน เครื่องอ่าน IC Chip เครื่องอ่านลายนิ้วมือ พร้อมทั้งการติดตั้ง การบำรุงรักษาและซ่อมแซม 5. ให้บริการติดตั้ง ซ่อมแซมและบำรุงรักษาเครื่องจักร อุปกรณ์ และอะไหล่ที่ใช้ในอุตสาหกรรมการพิมพ์ รวมทั้งคอมพิวเตอร์ เครื่องบันทึกเวลา เครื่องควบคุมการเปิดปิดประตู เครื่องอ่านจดจำใบหน้า เครื่องอ่านจดจำป้ายทะเบียน เครื่องอ่าน IC Chip และเครื่องอ่านลายนิ้วมือ 6. ให้บริการออกแบบและพัฒนา โปรแกรมคอมพิวเตอร์และระบบที่ใช้ในการรักษาความปลอดภัยข้อมูลสารสนเทศ การจัดการฐานข้อมูล การสื่อสารและบริหารจัดการเครือข่ายคอมพิวเตอร์', '218', '4', '-', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04101', 2198660000, 393, 6836, '2211', 'น.41(1)-1/2537-นนล.', 'Thailand'),
	('82030700125527', 'บริษัท ไซแมท เลเบล จำกัด', 'บริษัท ไซแมท เลเบล จำกัด', 'ผลิตและแปรรูปสติกเกอร์ เลเบลและบรรจุภัณฑ์', '123', '0', 'ฉลองกรุง31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04101', 356420000, 111, 56, NULL, 'น.41(1)-1/2552-นนล.', 'Thailand'),
	('72030000125278', 'บริษัท ซันโก้เคมิคอลส์ จำกัด', 'บริษัท ซันโก้เคมิคอลส์ จำกัด', 'สี ทินเนอร์สำหรับแลคเคอร์และสีที่ใช้ในอุตสาหกรรมทุกชนิด', '65', '4', 'นิคมอุตสาหกรรมลาดกระบัง', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04501', 26000000, 85, 710, '2422', 'น.45(1)-1/2527-ญนล.', 'Thailand'),
	('72030000125427', 'บริษัท สีเดลต้า จำกัด (มหาชน)', 'บริษัท สีเดลต้า จำกัด (มหาชน)', 'สีน้ำพลาสติกและสีน้ำมัน', '157', '0', 'ฉลองกรุง31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04501', 0, 182, 1267, '2422', 'น.45(1)-1/2542-ญนล.', 'Thailand'),
	('82030000225373', 'บริษัท เน็กซัส สเปเชี่ยล เพ้นท์ แอนด์ เคมิคอล (ประเทศไทย) จำกัด', 'บริษัท เน็กซัส สเปเชี่ยล เพ้นท์ แอนด์ เคมิคอล (ประเทศไทย) จำกัด', 'ผลิตสี ทินเนอร์  แลคเกอร์ น้ำมันผสมสี', '180', '0', 'ฉลองกรุง 31', '-', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04501', 97110000, 23, 116, '2422', 'น.45(1)-2/2537-นนล.', 'Thailand'),
	('82030400125538', 'บริษัท ไทยเมจิฟาร์มาซิวติคัล จำกัด', 'บริษัท ไทยเมจิฟาร์มาซิวติคัล จำกัด', 'ผลิตยาสำเร็จรูป เภสัชเคมีภัณฑ์ และผลิตภัณฑ์เสริมอาหาร ผลิตไฟฟ้าจากแสงอาทิตย์ เพื่อใช้เป็นสาธารณูปโภค ภายในบริษัทฯ กำลังการผลิต 877.92 กิโลวัตต์', '37', '0', 'ฉลองกรุง31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04601', 2598780000, 304, 4235, '2423', 'น.46(1)-1/2553-นนล.', 'Thailand'),
	('72030000125310', 'บริษัท ฟาร์มาแคร์ จำกัด', 'บริษัท ฟาร์มาแคร์ จำกัด', 'ผลิตเภสัชผลิตภัณฑ์ รวมถึงให้เช่าที่ดินพร้อมอาคาร, ผลิตไฟฟ้าจากแสงอาทิตย์ กำลังการผลิต 301.4 กิโลวัตต์ เพื่อใช้เป็นสาธารณูปโภคภายในโรงงาน', '114', '0', 'ฉลองกรุง 31', '-', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04602', 633890000, 168, 505, '2423', 'น.46(2)-1/2531-ญนล.', 'Thailand'),
	('72030100125251', 'บริษัท ยูนิลีเวอร์ ไทย โฮลดิ้งส์ จำกัด', 'บริษัท ยูนิลีเวอร์ ไทย โฮลดิ้งส์ จำกัด', '(1) ผลิตวัตถุดิบผงซักฟอก แชมพู ครีมนวดผม น้ำยาล้างภาชนะ ผงขัดภาชนะ น้ำยาซักผ้า ผงซักฟอก น้ำยาปรับผ้านุ่ม สบู่ ยาสีฟัน ผลิตกลีเซอรีนดิบ และกลีเซอรีนบริสุทธิ์ ผลิตภัณฑ์ใส่ผม ครีมล้างภาชนะ โลชั่นทาผิว และโฟมล้างหน้า (2) บริการปรับคุณภาพน้ำเสียซึ่งเป็นน้ำเสียไม่อันตรายให้แก่ บริษัท แม็กนั่ม ไอซีซี (ไทยแลนด์) จำกัด ที่ประกอบกิจการในนิคมอุตสาหกรรมลาดกระบัง  (3) บริการให้คำปรึกษา/แนะนำ/บริหารจัดการ ในการประกอบอุตสาหกรรมสำหรับการผลิตไอศกรีม ในด้านการจัดการ ด้านการตลาด ด้านทรัพยากรบุคคล ด้านเทคโนโลยีสนเทศ ที่เกี่ยวข้องให้แก่บริษัท แม็กนั่ม ไอซีซี (ไทยแลนด์) จำกัด  (4) บริการให้เช่าที่ดิน อาคารสำนักงานหรือศูนย์วิจัยบางส่วน อาคารคลังสินค้าบางส่วน อาคารโรงอาหารบางส่วน และอาคารจอดรถบางส่วนของบริษัทซึ่งสถานที่ให้เช่าตั้งอยู่ในนิคมอุตสาหกรรมลาดกระบัง พร้อมสาธารณูปโภคและสิ่งอำนวยความสะดวกที่เกี่ยวข้องให้แก่บริษัท แม็กนั่ม ไอซีซี (ไทยแลนด์) จำกัด ที่ประกอบกิจการในนิคมอุตสาหกรรมลาดกระบัง  (5) บริการให้ใช้ระบบและอุปกรณ์สำหรับการตรวจสอบคุณภาพสินค้าให้แก่ บริษัท แม็กนั่ม ไอซีซี (ไทยแลนด์) จำกัด ที่ประกอบกิจการในนิคมอุตสาหกรรมลาดกระบัง', '38', '0', NULL, 'ฉลองกรุง 31', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04701', 23377130000, 1054, 10580, '2424', 'น.47(1)-1/2525-ญนล.', 'Thailand'),
	('82030400125488', 'บริษัท พิคาโซ่ เนเชอรัลส์ แลบบอราทอรี่ จำกัด', 'บริษัท พิคาโซ่ เนเชอรัลส์ แลบบอราทอรี่ จำกัด', 'ซื้อมาขายไป นำเข้าส่งออก บรรจุ แบ่งบรรจุ ผลิตเครื่องสำอาง วัตถุดิบในการผลิตเครื่องสำอาง เครื่องสำอาง เช่น สบู่ แชมพู โลชั่นแป้ง น้ำหอม โคโลญจ์ และเครื่องปรุงแต่งร่างกายทุกชนิด รวมถึงวัสดุอุปกรณ์ บรรจุภัณฑ์ ส่วนประกอบบรรจุภัณฑ์ เครื่องจักรวัสดุ อุปกรณ์ ส่วนประกอบของเครื่องจักรที่ใช้ในการผลิตเครื่องสำอางทุกชนิด, ผลิตกระแสไฟฟ้าจากพลังงานแสงอาทิตย์สำหรับใช้เป็นสาธารณูปโภค ภายในบริษัท กำลังผลิตรวมสูงสุด 128.80 กิโลวัตต์, ให้เช่าที่ดิน อาคารโรงงาน สำนักงาน พร้อมทั้งสาธารณูปโภคและสิ่งอำนวยความสะดวกที่เกี่ยวข้องกับการให้เช่าดังกล่าว', '248', '0', 'ฉลองกรุง 31 นิคมอุตสาหกรรมลาดกระบัง', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04701', 92000000, 180, 449, '2424', 'น.47(1)-1/2548-นนล.', 'Thailand'),
	('82030100125523', 'บริษัท กรีนสวิลล์ จำกัด (โรงงาน 2)', 'บริษัท กรีนสวิลล์ จำกัด (โรงงาน 2)', 'ผลิตเครื่องสําอาง, ผลิตภัณฑ์ทําความสะอาดและผลิตยาสีฟัน, ผลิตไฟฟ้าจากแสงอาทิตย์เพื่อใช้ในโรงงาน กําลังการผลิต 649.185 กิโลวัตต์', '33,34', '0', NULL, NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04701', 262630000, 193, 2439, '2424', 'น.47(1)-1/2552-นนล.', 'Thailand'),
	('82030200125597', 'บริษัท พิคาโซ่ เนเชอรัลส์ แลบบอราทอรี่ จำกัด', 'บริษัท พิคาโซ่ เนเชอรัลส์ แลบบอราทอรี่ จำกัด', 'ซื้อมาขายไป นำเข้าส่งออกบรรจุแบ่งบรรจุเครื่องสำอางวัตถุดิบในการผลิตเครื่องสำอาง เครื่องสำอาง เช่น สบู่ แชมพู โลชั่น แป้ง น้ำหอม โคโลญจ์ และเครื่องปรุงแต่งร่างกายทุกชนิด', '187', '0', 'ฉลองกรุง 31 นิคมอุตสาหกรรมลาดกระบัง', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04701', 245700000, 159, 158, '2424', 'น.47(1)-1/2559-นนล.', 'Thailand'),
	('72030000225326', 'บริษัท กรีนสวิลล์ จำกัด (โรงงาน 1)', 'บริษัท กรีนสวิลล์ จำกัด (โรงงาน 1)', 'ผลิตเครื่องสำอาง, ผลิตไฟฟ้าจากแสงอาทิตย์เพื่อใช้ในโรงงาน กำลังการผลิต 124.3 กิโลวัตต์', '31', '0', 'ฉลองกรุง 31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04701', 393760000, 52, 1821, '2424', 'น.47(1)-2/2532-ญนล.', 'Thailand'),
	('82030017325638', 'บริษัท เอ-พลัส ซัพพลาย จำกัด', 'บริษัท เอ-พลัส ซัพพลาย จำกัด', 'ผลิต และนำเข้าส่งออก สบู่ ครีมอาบน้ำ ครีมทาผิว เกลือขัดผิว', '4/59', '0', 'ฉลองกรุง 31', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04701', 71000000, 244, 302, NULL, 'น.47(1)-173/2536-นนล.', 'Thailand'),
	('72030200125284', 'บริษัท ริโอเท็กซ์ โพลิเมอร์ จำกัด', 'บริษัท ริโอเท็กซ์ โพลิเมอร์ จำกัด', 'ผลิตกาวเรซินและเคมีภัณฑ์', '68', '4', '-', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04803', 7500000, 25, 1326, '2429', 'น.48(3)-1/2528-ญนล.', 'Thailand'),
	('72030000325357', 'บริษัท 3 เอ็ม ประเทศไทย จำกัด', 'บริษัท 3 เอ็ม ประเทศไทย จำกัด', 'ผลิตแถบกาว กาวยาง แผ่นใยขัดถู กระดาษทราย สติกเกอร์ แผ่นสะท้อนแสง ไส้กรอง และยางสังเคราะห์ฟลูออโรอีลาสโตเมอร์', '150', '0', 'ฉลองกรุง 31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04803', 172500000, 111, 1923, '3699', 'น.48(3)-3/2535-ญนล.', 'Thailand'),
	('72030000125377', 'บริษัท เซโค แอดวานซ์ (ประเทศไทย) จำกัด', 'บริษัท เซโค แอดวานซ์ (ประเทศไทย) จำกัด', 'ผลิตหมึกพิมพ์  ซิลสกรีน', '147,147/1', '0', 'ฉลองกรุง31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '04806', 585400000, 43, 1145, '2429', 'น.48(6)-1/2537-ญนล.', 'Thailand'),
	('72030000125286', 'บริษัท แอนเซลล์ (ประเทศไทย) จำกัด', 'บริษัท แอนเซลล์ (ประเทศไทย) จำกัด', 'ผลิตผลิตภัณฑ์ยาง(ถุงมือยาง ลูกโป่ง และลูกบัลลูน) ประกอบกิจการบรรจุผลิตภัณฑ์ จำหน่ายสารเคมีและการมอบสารเคมีที่เกี่ยวกับการผลิตเพื่อการทดสอบ', '74', '0', 'ฉลองกรุง 31', '-', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '05202', 3038990000, 552, 34970, '2519', 'น.52(2)-1/2528-ญนล.', 'Thailand'),
