	('72030000225318', 'บริษัท อีซูซุเอ็นยิ่น แมนูแฟคเจอริ่ง (ประเทศไทย) จำกัด', 'บริษัท อีซูซุเอ็นยิ่น แมนูแฟคเจอริ่ง (ประเทศไทย) จำกัด', 'ผลิตหรือประกอบเครื่องยนต์ดีเซลอุปกรณ์ชิ้นส่วนเครื่องยนต์ดีเซลและอุปกรณ์ชิ้นส่วนรถยนต์ ได้แก่ ฝาครอบเสื้อคลัทช์ (CLUTH HOUSING) เพลาล้อหน้า (KNUCKLE) ชุดเฟืองท้าย (FINAL DRIVE) เพลาหน้า (FRONT AXLE) , ประกอบ ดัดแปลง ซ่อมแซม เครื่องยนต์และอุปกรณ์ชิ้นส่วนเครื่องยนต์ หรืออุปกรณ์ชิ้นส่วนรถยนต์ทุกชนิด , ผลิตพลังงานไฟฟ้าจากพลังงานแสงอาทิตย์กำลังการผลิต 6,928.30 กิโลวัตต์ เพื่อใช้ในอาคารโรงงาน บริเวณที่จอดรถ ที่พักพนักงาน และโรงอาหาร', '131, 133', '0', 'ฉลองกรุง31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '06500', 25142510000, 807, 110597, '291', 'น.65-2/2531-ญนล.', 'Thailand'),
	('72030200325348', 'บริษัท อ๊าร์ท-เสรีนา ปิสตัน จำกัด', 'บริษัท อ๊าร์ท-เสรีนา ปิสตัน จำกัด', 'ผลิตลูกสูบเครื่องยนต์ทุกชนิด', '169', '0', 'ฉลองกรุง 31', '-', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '06500', 2878500000, 380, 4818, '2911', 'น.65-3/2534-ญนล.', 'Thailand'),
	('72030000325548', 'บริษัท ไทยฮอนด้า จำกัด', 'บริษัท ไทยฮอนด้า จำกัด', 'ผลิตเครื่องยนต์อเนกประสงค์', '137 นิคมอุตสาหกรรมลาดกระบัง', '0', '-', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '06500', 0, 3638, 0, NULL, 'น.65-3/2554-ญนล.', 'Thailand'),
	('72030000125237', 'บริษัท ยันม่าร์ เอส.พี. จำกัด', 'บริษัท ยันม่าร์ เอส.พี. จำกัด', 'ซื้อมาขายไป ผลิต ประกอบ ซ่อมแซม เครื่องยนต์ดีเซล,แกสโซลีนทุกชนิด เครื่องยนต์เรือ อะไหล่ และอุปกรณ์ ของผลิตภัณฑ์ดังกล่าวทุกชนิดและประกอบรถแทรกเตอร์', '115', '0', 'ฉลองกรุง 31', '-', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '06600', 5906560000, 404, 1507, '3511', 'น.66-1/2523-ญนล.', 'Thailand'),
	('72030100125426', 'บริษัท อซาด้า แมชชินเนอรี่ จำกัด', 'บริษัท อซาด้า แมชชินเนอรี่ จำกัด', 'ซ่อมแซม เครื่องจักรประเภทเครื่องต๊าบเกลียวไฟฟ้า เครื่องเลื่อย ปั๊มอัดฉีด', '27', '0', 'ฉลองกรุง 31', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '06702', 297370000, 121, 1337, '2930', 'น.67(2)-1/2542-ญนล.', 'Thailand'),
	('82030400125553', 'บริษัท เวอร์ทิว เทคโนโลยี่ จำกัด', 'บริษัท เวอร์ทิว เทคโนโลยี่ จำกัด', 'นำเข้า-ส่งออกผลิตเครื่องจักรกล อะไหล่อุปกรณ์ชิ้นส่วนเครื่องจักรกล อุปกรณ์เครื่องตรึงใช้ยึดจับ เจาะ วัตถุสำหรับกลึง หรืออุปกรณ์จับชิ้นงานในระหว่างกระบวนการผลิตแม่พิมพ์ แบบพิมพ์และปากกาจับวัตถุทุกชนิด', '327', '0', NULL, 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '06707', 8000000, 32, 206, '2922', 'น.67(7)-1/2555-นนล.', 'Thailand'),
	('72030000325332', 'บริษัท โอกิฮาร่า (ประเทศไทย) จำกัด', 'บริษัท โอกิฮาร่า (ประเทศไทย) จำกัด', 'ผลิตแม่พิมพ์ (MOLDS AND DIES)  ผลิตตัวอย่างชิ้นส่วนรถยนต์ (AUTOMOBILE SAMPLE  PARTS) และผลิตชิ้นส่วนยานยนต์ (AUTOMOBILE PARTS)', '172', '0', 'ฉลองกรุง 31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '06707', 2296290000, 432, 4425, '3591', 'น.67(7)-3/2533-ญนล.', 'Thailand'),
	('82030027225687', 'บริษัท เอเวสท์ จำกัด', 'บริษัท เอเวสท์ จำกัด', '1. รับจ้างผลิต ซ่อมแซม เครื่องจักร เครื่องมือ วัตถุดิบ แผ่นพิมพ์วงจรไฟฟ้าอิเล็กทรอนิกส์2. ซื้อมา-ขายไป เครื่องจักร เครื่องมือ วัตถุดิบและอุปกรณ์แผ่นพิมพ์วงจรไฟฟ้าอิเล็กทรอนิกส์ทุกชนิด', '45 อาคาร', '0', 'ฉลองกรุง 31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '06708', 41000000, 13, 168, NULL, 'น.67(8)-272/2568-นนล.', 'Thailand'),
	('82030100125580', 'บริษัท อีไอซี เซมิคอนดักเตอร์ จำกัด', 'บริษัท อีไอซี เซมิคอนดักเตอร์ จำกัด', '1. ผลิตและแยกอะไหล่ ชิ้นส่วนอิเล็กทรอนิกส์ (เช่น DIODE, TRANSISTOR, I.C. เป็นต้น) 2. แบ่งบรรจุสินค้าอุปโภคบริโภค สุรา ยาสูบ เครื่องสำอาง เครื่องใช้ไฟฟ้าในบ้าน ไฟแช็ก เครื่องใช้ในครัวเรือน เครื่องแต่งกายของเด็กเล่น 3. ซื้อมาขายไปเม็ดพลาสติก เครื่องอิเล็กทรอนิกส์ รวมถึงชิ้นส่วนอุปกรณ์และอะไหล่อิเล็กทรอนิกส์ 4. ผลิตกระแสไฟฟ้า (ดัดแปลงอาคารโดยติดตั้งแผง SOLAR ROOFTOR บนหลังคาพื้นที่ประมาณ 3,250 ตารางเมตร) กำลังการผลิต 0.43 เมกะวัตต์ เพื่อใช้ภายในอาคาร', '65,68', '0', 'ฉลองกรุง  31', NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '06900', 282890000, 185, 1376, NULL, 'น.69-1/2558-นนล.', 'Thailand'),
	('72030000125294', 'บริษัท กุลธรเคอร์บี้ จำกัด (มหาชน)', 'บริษัท กุลธรเคอร์บี้ จำกัด (มหาชน)', 'ผลิตมอเตอร์คอมเพรสเซอร์ และอุปกรณ์ชิ้นส่วนมอเตอร์คอมเพรสเซอร์ และอุปกรณ์เครื่องทำความเย็น (Condensing Unit)', '126', '0', 'ฉลองกรุง31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '07100', 6327970000, 598, 22710, '2912', 'น.71-1/2529-ญนล.', 'Thailand'),
