	('72030000325597', 'บริษัท เอ็นเอส-โอจี เอนเนอร์จี โซลูชั่นส์ (ไทยแลนด์) จำกัด', 'บริษัท เอ็นเอส-โอจี เอนเนอร์จี โซลูชั่นส์ (ไทยแลนด์) จำกัด', 'ผลิตกระแสไฟฟ้าจากก๊าซธรรมชาติ กำลังการผลิต 7.8 เมกะวัตต์ ไอน้ำ น้ำร้อนและน้ำเย็น', '410', '0', NULL, 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '08802', 511010000, 256, 25513, '4100', 'น.88(2)-3/2559-ญนล.', 'Thailand'),
	('72030001425578', 'บริษัท พีพีทีซี จำกัด', 'บริษัท พีพีทีซี จำกัด', 'ผลิตกระแสไฟฟ้าโดยใช้ก๊าซธรรมชาติเป็นเชื้อเพลิง ขนาดกำลังการผลิตสูงสุด 136.44 เมกะวัตต์ และไอน้ำ 30 ตัน/ชั่วโมง เพื่อเป็นระบบสาธารณูปโภค', '99/9', '0', 'ฉลองกรุง 31', 'ฉลองกรุง', 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '08802', 5580000000, 40, 133362, '4030', 'น.88(2)-14/2557-ญนล.', 'Thailand'),
	('82030700125568', 'บริษัท เจม เอ็นไวรันเมนทัล แมเนจเม้นท์  จำกัด', 'บริษัท เจม เอ็นไวรันเมนทัล แมเนจเม้นท์ จำกัด', 'โรงผลิตน้ำเพื่อการอุตสาหกรรม,โรงผลิตน้ำเพื่อการอุตสาหกรรม , ผลิตไฟฟ้าจากแสงอาทิตย์ กำลังการผลิต 70 กิโลวัตต์', '173', '0', NULL, NULL, 'ลำปลาทิว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '09000', 251640000, 11, 516, '4100', 'น.90-1/2556-นนล.', 'Thailand'),
