	('10100001825484', 'สมคิดค้าไม้', 'นายสคิด กิตติวงศ์สถาพร', 'ไส-ซอยไม้ ทำวงกบ บานประตู-หน้าต่าง เครื่องใช้และต่อเรือไม้', '549/2', '1', NULL, 'หลวงแพ่ง', 'ทับยาว', 'ลาดกระบัง', 'Bangkok', '10520', NULL, '03401', 8200000, 12, 196.5, '16101', '3-34(1)-18/48', 'Thailand'),
