	('82160011525683', 'บริษัท เมกแมน จิวเวลรี่ จำกัด', 'บริษัท เมกแมน จิวเวลรี่ จำกัด', 'ผลิตจิวเวลรี่และจำหน่ายเครื่องประดับจากอัญมณีและโลหะที่มีค่า', '64/38 อาคาร', '0', 'สุขาภิบาล 2 ซอย 31', NULL, 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 12000000, 11, 39, NULL, 'น.84(1)-115/2568-นอธ.', 'Thailand'),
	('82160011825687', 'บริษัท ครีเอทีฟ จิวเวลรี่ แมนูแฟคเจอริ่ง จำกัด', 'บริษัท ครีเอทีฟ จิวเวลรี่ แมนูแฟคเจอริ่ง จำกัด', 'ผลิต ออกแบบ จัดทำ ซื้อขาย แลกเปลี่ยน ซ่อมแซม ปรับปรุงสภาพ และนำเข้าส่งออก เครื่องประดับ อัญมณีทุกชนิด เงิน ทอง นาก เพชรพลอย ไข่มุก ทองแดง ทองเหลือง แพลตทินัม และอัญมณีอื่นๆ ทุกประเภทรวมทั้งวัตถุทำเทียมสิ่งดั่งกล่าว', '70', '0', 'สุขาภิบาล2 ซอย31', '-', 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 16810000, 68, 196, NULL, 'น.84(1)-118/2568-นอธ.', 'Thailand'),
	('82160012225671', 'บริษัท โมเสค จิวเวลรี่ จำกัด', 'บริษัท โมเสค จิวเวลรี่ จำกัด', 'ผลิต ทอง เงิน อัญมณีและเครื่องประดับอื่นๆ ทุกชนิด', '66/40', '0', 'สุขาภิบาล 2 ซอย 31', NULL, 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 3000000, 12, 51, NULL, 'น.84(1)-122/2567-นอธ.', 'Thailand'),
	('82160012725639', 'บริษัท เดอะ สตูดิโอ - บีเคเค จำกัด', 'บริษัท เดอะ สตูดิโอ - บีเคเค จำกัด', '1.ผลิตเครื่องประดับโดยใช้เพชร พลอยไข่มุก ทองคํา ทองขาว เงิน นาก หรืออัญมณีอย่างใดอย่างหนึ่ง หรือหลายอย่าง 2.นำเข้าเครื่องประดับเพชรพลอย ทอง เงินนาก หรืออัญมณีเพื่อซ่อมและส่งออกไปยังบริษัทแม่ที่ประเทศสหรัฐอเมริกา 3.ให้บริการตรวจสอบควบคุมคุณภาพเครื่องประดับที่ผลิตโดยโรงงานคู่ค้าของบริบัทแม่ก่อนส่งออกไปยังบริบัทแม่ที่ประเทศสหรัฐอเมริกา 4.ให้บริการจัดหาวัตถุดิบเพชร, พลอยไข่มุก, ทองคํา, ทองขาว, เงิน, นาก, หรืออัญมณีอย่างใดอย่างหนึ่ง หรือหลายอย่าง, ฉลากและบรรจุภัณท์ สำหรับการผลิตเครื่องประดับและกระจายไปยังโรงงานคู่ค้าของบริบัทแม่เพื่อทำการผลิตเครื่องประดับและส่งออกไปยังบริบัทแม่ที่ประเทศสหรัฐอเมริกา 5.ให้บริการผลิตแม่พิมพ์เครื่องประดับ', '64/36', '0', 'สุขาภิบาล 2 ซอย 31', 'สุขาภิบาล', 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 27710000, 34, 46, NULL, 'น.84(1)-127/2563-ญอธ.', 'Thailand'),
