	('82160018125685', 'บริษัท อิลิแกนท์ ไทย จำกัด', 'บริษัท อิลิแกนท์ ไทย จำกัด', 'ผลิต เงิน ทอง นาก เพชร พลอย อัญมณีอื่นๆ และเครื่องประดับทุกชนิด รวมทั้งวัตถุทำเทียมสิ่งดังกล่าว', '68/22', '0', 'สุขาภิบาล 2 ซอย 31', NULL, 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 0, 5, 150, NULL, 'น.84(1)-181/2568-นอธ.', 'Thailand'),
	('72160018925656', 'บริษัท เจมแบรนด์ จิวเวลเลอรี่ จำกัด', 'บริษัท เจมแบรนด์ จิวเวลเลอรี่ จำกัด', 'ผลิตและจำหน่าย ทอง นาก เงิน เพชร พลอย และอัญมณีอื่นรวมทั้งวัตถุทำเทียมสิ่งดังกล่าว', '58  อาคาร', '0', 'สุขาภิบาล 2 ซอย 31', '-', 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 9720000, 8, 27, NULL, 'น.84(1)-189/2565-ญอธ.', 'Thailand'),
	('82160019425670', 'บริษัท วิวานต้า จิวเวลรี่ จำกัด', 'บริษัท วิวานต้า จิวเวลรี่ จำกัด', 'ผลิต นำเข้า ส่งออก เงิน ทอง นาก เพชร พลอย ไข่มุก ทองแดง ทองเหลือง แพลตทินั่ม อัญมณีและเครื่องประดับทุกชนิด รวมทั้งวัตถุทำเทียมสิ่งดังกล่าว', '92/29', '0', 'สุขาภิบาล 2 ซอย 31', NULL, 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 0, 5, 55, NULL, 'น.84(1)-194/2567-นอธ.', 'Thailand'),
	('72160021325639', 'บริษัท เดโลรา จำกัด', 'บริษัท เดโลรา จำกัด', 'ผลิตเครื่องประดับอัญมณี', '8/7 อาคาร', '0', 'สุขาภิบาล2 ซอย 31', NULL, 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 73790000, 36, 180, NULL, 'น.84(1)-213/2563-ญอธ.', 'Thailand'),
	('72140021625634', 'บริษัท วินซิลเวอร์ จำกัด', 'บริษัท วินซิลเวอร์ จำกัด', '1. ผลิตและซื้อมาขายไปเครื่องประดับอัญมณีทุกชนิด 2. ซื้อมาขายไปเครื่องมือเครื่องใช้ในการจัดแสดงสินค้า เพื่อส่งเสริมการขายสำหรับเครื่องประดับทุกชนิด', '66/15-18', '0', 'สุขาภิบาล 2 ซอย 31', '-', 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 14000000, 71, 29, NULL, 'น.84(1)-216/2563-ญอธ.', 'Thailand'),
	('82160022025673', 'บริษัท เจแปน จิวเวลรี่ แฟคตอรี่ จำกัด', 'บริษัท เจแปน จิวเวลรี่ แฟคตอรี่ จำกัด', '1. ผลิตและรับจ้างผลิตเครื่องประดับที่ทำมาจากทอง เงิน โลหะผสม เพชร พลอย และหินมีค่า 2. บริการออกแบบ รับจ้างออกแบบ เครื่องประดับทุกชนิด', '92/14-15 อาคาร', '0', 'สุขาภิบาล 2 ซอย 31', '-', 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 24200000, 31, 53, NULL, 'น.84(1)-220/2567-นอธ.', 'Thailand'),
	('72160022525641', 'บริษัท ยู-อินเตอร์เนชั่นแนล แฟคตอรี่ จำกัด', 'บริษัท ยู-อินเตอร์เนชั่นแนล แฟคตอรี่ จำกัด', '1. ผลิตและรับจ้างผลิต อัญมณีและเครื่องประดับ ที่ทำจากอัญมณีทุกชนิด เงิน ทอง นาก เพชร พลอย ไข่มุก ทองแดง ทองเหลือง แพลตตินั่ม และอัญมณีอื่นๆ รวมทั้งวัตถุทำเทียมดังกล่าว  2. ประกอบกิจการ ผลิตและส่งออก เครื่องแต่งกาย เครื่องหนัง นาฬิกา รองเท้า กระเป๋าและเข็มขัด  3. รับจ้างเจียระไน อัญมณีทุกชนิด เพชร พลอย', '60', '0', 'สุขาภิบาล 2 ซอย 31', '-', 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 4500000, 32, 133, NULL, 'น.84(1)-225/2564-ญอธ.', 'Thailand'),
	('72160022625631', 'บริษัท อาร์ธา จิวเวลรี่ จำกัด', 'บริษัท อาร์ธา จิวเวลรี่ จำกัด', 'ผลิตเครื่องประดับ อัญมณี ทุกประเภท , จำหน่าย นำเข้าและส่งออกเครื่องประดับ อัญมณี ทุกประเภท', '66/39', '0', 'สุขาภิบาล 2 ซอย 31', '-', 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 1000000, 23, 60, NULL, 'น.84(1)-226/2563-ญอธ.', 'Thailand'),
	('72160023125649', 'บริษัท กัลวาเทค จำกัด', 'บริษัท กัลวาเทค จำกัด', 'จัดซื้อ นำเข้า ส่งออก ผลิต จำหน่ายและรับจ้างผลิตเครื่องประดับและอัญมณีทุกชนิด รวมถึงการบรรจุ ประกอบ ขัด เคลือบผิว การปรับหรือเปลี่ยนสภาพผิว และชุบเครื่องประดับและอัญมณีทุกชนิด', '64/20-21 นิคมอุตสาหกรรมอัญธานี ฟรีโซน ชั้นที่ 2', '0', 'สุขาภิบาล 2 ซอย 31', '-', 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 1000000, 13, 51, NULL, 'น.84(1)-231/2564-ญอธ.', 'Thailand'),
	('72160023725653', 'บริษัท มาสเตอร์พีซ ไดมอนด์ส เอ็มเอฟจี จำกัด', 'บริษัท มาสเตอร์พีซ ไดมอนด์ส เอ็มเอฟจี จำกัด', 'ผลิต นำเข้า ส่งออก หินสี เพชร พลอย อัญมณีต่างๆ และเครื่องประดับที่ทำจากอัญมณีต่างๆ', '68/7,8,9,10,14', '0', 'สุขาภิบาล 2 ซอย 31', '-', 'ดอกไม้', 'ประเวศ', 'Bangkok', '10250', NULL, '08401', 2000000, 48, 0, NULL, 'น.84(1)-237/2565-ญอธ.', 'Thailand'),
